+    setSelectedProviderId((current) => providers.some((provider) => provider.id === current) ? current : fallback?.id ?? "");
+  }, [settings]);
+
+  useEffect(() => {
+    if (!selectedProvider) {
+      setSelectedModel("");
+      return;
+    }
+    const models = selectedProvider.models.length ? selectedProvider.models : [selectedProvider.defaultModel];
