+      <section className="topbar">
+        <div className="mark" aria-hidden="true">
+          <Sparkles size={17} />
+        </div>
+        <div className="brand-copy">
+          <div className="brand-title">{t.aiBrowserConsole}</div>
+          <div className="brand-subtitle">Agenticify</div>
+        </div>
